import psycopg2
from typing import Optional, Dict, Any

def search_users(connection, username: Optional[str] = None, email: Optional[str] = None, 
                role: Optional[str] = None, status: Optional[str] = None) -> list:
    """
    Fetch user profiles from PostgreSQL database based on multiple filter criteria.
    
    Args:
        connection: psycopg2 database connection object
        username: Optional username filter
        email: Optional email filter
        role: Optional role filter (admin/user/guest)
        status: Optional status filter (active/suspended)
    
    Returns:
        List of user profile dictionaries
    """
    # Build the WHERE clause dynamically
    conditions = []
    params = []
    
    if username is not None:
        conditions.append("username = %s")
        params.append(username)
    
    if email is not None:
        conditions.append("email = %s")
        params.append(email)
    
    if role is not None:
        conditions.append("role = %s")
        params.append(role)
    
    if status is not None:
        conditions.append("status = %s")
        params.append(status)
    
    # Construct the query
    if conditions:
        where_clause = " AND ".join(conditions)
        query = f"SELECT * FROM users WHERE {where_clause}"
    else:
        query = "SELECT * FROM users"
    
    # Execute the query with parameters
    with connection.cursor() as cursor:
        cursor.execute(query, tuple(params))
        columns = [desc[0] for desc in cursor.description]
        results = cursor.fetchall()
        
        # Convert to list of dictionaries
        return [dict(zip(columns, row)) for row in results]

